refentry.refsect1:
  &reftitle.description;

&style.oop;
  arraymysqli->error_list

&style.procedural;

   arraymysqli_error_list
   mysqlimysql



   Функция возвращает массив ошибок последнего вызова функции модуля MySQLi,
   даже если функция завершилась без ошибок.

  &reftitle.examples;

   Пример получения списка ошибок функцией $mysqli->error_list

&style.oop;


<?php

$mysqli = new mysqli("localhost", "nobody", "");

/* Проверяем соединение */
if (mysqli_connect_errno()) {
    printf("При подключении возникла ошибка: %s\n", mysqli_connect_error());
    exit();
}

if (!$mysqli->query("SET a=1")) {
    print_r($mysqli->error_list);
}

/* Закрываем соединение */
$mysqli->close();



&style.procedural;


<?php

$link = mysqli_connect("localhost", "my_user", "my_password", "world");

/* Проверяем соединение */
if (mysqli_connect_errno()) {
    printf("При подключении возникла ошибка: %s\n", mysqli_connect_error());
    exit();
}

if (!mysqli_query($link, "SET a=1")) {
    print_r(mysqli_error_list($link));
}

/* Закрываем соединение */
mysqli_close($link);


   &examples.outputs;


Array
(
    [0] => Array
        (
            [errno] => 1193
            [sqlstate] => HY000
            [error] => Unknown system variable 'a'
        )

)
